import click
from click.testing import CliRunner

@click.command()
@click.option('--item', multiple=True, batch_size=2)
def cli(item):
    for batch in item:
        click.echo(repr(batch))

runner = CliRunner()
result = runner.invoke(cli, ['--item', 'a', '--item', 'b', '--item', 'c', '--item', 'd', '--item', 'e'], catch_exceptions=False)
print(result.output)

# no batch_size, backward compatible
@click.command()
@click.option('--item', multiple=True)
def cli2(item):
    click.echo(repr(item))

result2 = runner.invoke(cli2, ['--item', 'a', '--item', 'b'], catch_exceptions=False)
print(result2.output)
"
